Here are the complete and robust Firestore security rules for your application, designed to secure user data, wallet balances, and system configurations while permitting the necessary logic for your app (like automated ROI, referral commissions, and giveaways) to function correctly.

You can copy and paste this directly into your `firestore.rules` file in the Firebase Console or your local project.

```javascript
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- HELPER FUNCTIONS ---

    // Check if the user is authenticated
    function isSignedIn() {
      return request.auth != null;
    }

    // Check if the user is accessing their own document
    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    // Check if the user has the 'isAdmin' flag set to true in their user profile
    function isAdmin() {
      return isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) &&
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true;
    }

    // --- COLLECTION RULES ---

    // USERS COLLECTION
    // Holds profile data, balances, and referral stats.
    match /users/{userId} {
      allow read: if isSignedIn();

      // Creation: Users can create their own profile on signup. 
      // Security: Prevent them from setting themselves as admin immediately.
      allow create: if isOwner(userId) && request.resource.data.isAdmin == false;

      // Update Rules:
      // 1. Owner can update fields (like withdrawal address), but cannot change isAdmin status.
      // 2. Admin can update any user (for bans, manual credits, etc).
      // 3. Referral/ROI Logic: Authenticated users (Uplines or Scripts) need to increment specific counters 
      //    on other users (like 'referralEarnings' or 'profitBalance') during transactions.
      //    We strictly limit which fields can be modified by non-owners/non-admins.
      allow update: if 
        (isOwner(userId) && request.resource.data.isAdmin == resource.data.isAdmin) || 
        isAdmin() ||
        (isSignedIn() && request.resource.data.diff(resource.data).affectedKeys()
          .hasOnly(['referralCount', 'profitBalance', 'referralEarnings', 'totalEarned', 'capitalBalance', 'whatsappShares', 'lastWhatsappShare']));
    }

    // REFERRALS COLLECTION
    // Tracks the linkage between a user and who referred them.
    match /referrals/{userId} {
      allow read: if isSignedIn();
      // Users create their own record when they sign up or when they purchase (linking stats).
      allow write: if isOwner(userId) || isAdmin();
    }

    // REFERRAL CODES COLLECTION
    // A global lookup map for referral codes to user IDs.
    match /referral_codes/{code} {
      // Open read needed so new users can resolve codes during signup before they are authenticated.
      allow read: if true;
      allow write: if isSignedIn();
    }

    // PACKAGES (NODES) COLLECTION
    // Defines the investment products.
    match /packages/{pkgId} {
      allow read: if true;
      // Only admins can manage the product catalog.
      allow write: if isAdmin();
    }

    // ACTIVE PACKAGES COLLECTION
    // Tracks purchased nodes for each user.
    match /activePackages/{apId} {
      // Users can see their own investments; Admins can see all.
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());

      // Users create a record when they buy a node.
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;

      // Users (via client-side ROI scripts) need to update 'lastPayoutAt' and 'totalEarned'.
      allow update: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());
    }

    // TRANSACTIONS COLLECTION
    // The ledger for all financial movements.
    match /transactions/{txId} {
      // Users see their own history; Admins see global ledger.
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());

      // Creation Logic:
      // 1. Users create their own transactions (Deposit, Withdrawal Request, ROI Credit).
      // 2. Referral Commissions: When User A buys a node, they create a 'REFERRAL' transaction 
      //    assigned to User B (their upline). We allow this specific cross-user creation.
      allow create: if isSignedIn() && (
        request.resource.data.userId == request.auth.uid || 
        request.resource.data.type == 'REFERRAL'
      );

      // Only admins can update transactions (e.g., marking a withdrawal as COMPLETED or REJECTED).
      allow update: if isAdmin();
    }

    // GIVEAWAY POOLS COLLECTION
    // Manages bonus codes.
    match /giveawayPools/{poolId} {
      allow read: if isSignedIn();
      allow create: if isAdmin();

      // Users need to increment 'claimsCount' when they successfully claim a code.
      // We restrict the update to ONLY the 'claimsCount' field to prevent tampering with amounts.
      allow update: if isAdmin() || (isSignedIn() && request.resource.data.diff(resource.data).affectedKeys().hasOnly(['claimsCount']));

      allow delete: if isAdmin();
    }

    // GIVEAWAY CLAIMS COLLECTION
    // Tracks who has claimed which code to prevent double-dipping.
    match /giveawayClaims/{claimId} {
      allow read: if isSignedIn() && resource.data.userId == request.auth.uid;
      // User creates a claim record for themselves.
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
    }

    // SYSTEM SETTINGS COLLECTION
    // Global app config (maintenance mode, referral percentages, etc).
    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // SYSTEM BANKS COLLECTION
    // For Fiat/NGN bank account details displayed to users.
    match /system_banks/{bankId} {
      allow read: if isSignedIn();
      allow write: if isAdmin();
    }

    // FIAT REQUESTS COLLECTION
    // For manual bank deposit/withdrawal requests.
    match /fiat_requests/{reqId} {
      // Users see their own requests; Admins see all to process them.
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());

      // Users create requests.
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;

      // Admins update status (Approve/Reject).
      allow update: if isAdmin();
    }

    // VAULT COLLECTION
    // Sensitive admin data (Hot Wallet Private Keys). Strictly Admin only.
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

