export const performWhatsappShareTask = async (userId: string) => {
  const settingsRef = doc(db, 'system', 'settings');
  const userRef = doc(db, 'users', userId);

  await runTransaction(db, async (transaction) => {
    const settingsSnap = await transaction.get(settingsRef);
    const userSnap = await transaction.get(userRef);

    if (!userSnap.exists()) throw new Error("User not found");
    const user = userSnap.data() as User;

    const settings = settingsSnap.exists() ? settingsSnap.data() : {};
    const taskConfig = settings.whatsappConfig as WhatsappTaskConfig | undefined;

    // 1. Check if Enabled
    if (!taskConfig || !taskConfig.enabled) {
      throw new Error("Task is currently disabled by administrator.");
    }

    // 2. Check Lifetime Limit
    const currentShares = user.whatsappShares || 0;
    if (currentShares >= taskConfig.maxLifetimeShares) {
      throw new Error(`Maximum lifetime shares (${taskConfig.maxLifetimeShares}) reached.`);
    }

    // 3. Check Cooldown
    const lastShare = user.lastWhatsappShare || 0;
    const now = Date.now();
    const cooldownMs = taskConfig.cooldownHours * 60 * 60 * 1000;
    const timeSinceLast = now - lastShare;

    if (timeSinceLast < cooldownMs) {
      const hoursRemaining = Math.ceil((cooldownMs - timeSinceLast) / (60 * 60 * 1000));
      throw new Error(`Cooldown active. Try again in ${hoursRemaining} hours.`);
    }

    // 4. Execute Reward
    transaction.update(userRef, {
      whatsappShares: increment(1),
      lastWhatsappShare: now,
      profitBalance: increment(taskConfig.rewardAmount),
      totalEarned: increment(taskConfig.rewardAmount)
    });

    const txRef = doc(collection(db, 'transactions'));
    transaction.set(txRef, {
      id: txRef.id,
      userId,
      type: TransactionType.TASK_REWARD,
      amount: taskConfig.rewardAmount,
      status: TransactionStatus.COMPLETED,
      timestamp: now,
      description: `Task Reward: WhatsApp Share`
    });
  });
};

rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // --- HELPER FUNCTIONS ---

    function isSignedIn() {
      return request.auth != null;
    }

    function isOwner(userId) {
      return isSignedIn() && request.auth.uid == userId;
    }

    function isAdmin() {
      return isSignedIn() && 
        exists(/databases/$(database)/documents/users/$(request.auth.uid)) &&
        get(/databases/$(database)/documents/users/$(request.auth.uid)).data.isAdmin == true;
    }

    // --- COLLECTION RULES ---

    // USERS
    match /users/{userId} {
      allow read: if isSignedIn();

      // Creation: User can create their own profile, but cannot make themselves Admin
      allow create: if isOwner(userId) && request.resource.data.isAdmin == false;

      // Update Rules:
      // 1. Owner can update their own profile (Balances, Withdrawal Address, etc), provided they don't change isAdmin status
      // 2. Admin can update anyone
      // 3. Referral System: Authenticated users can increment specific counters/balances on *other* users (Uplines)
      allow update: if 
        (isOwner(userId) && request.resource.data.isAdmin == resource.data.isAdmin) || 
        isAdmin() ||
        (isSignedIn() && request.resource.data.diff(resource.data).affectedKeys()
          .hasOnly(['referralCount', 'profitBalance', 'referralEarnings', 'totalEarned']));
    }

    // REFERRALS (Linkage Records & Personal Commission Tracking)
    match /referrals/{userId} {
      allow read: if isSignedIn();
      // Users create/update their own linkage record during purchase/signup
      allow write: if isOwner(userId) || isAdmin();
    }

    // REFERRAL CODES (Global Lookup)
    match /referral_codes/{code} {
      allow read: if true;
      allow write: if isSignedIn();
    }

    // PACKAGES (Nodes)
    match /packages/{pkgId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // ACTIVE PACKAGES (User Investments)
    match /activePackages/{apId} {
      // Users read their own, Admin reads all
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());

      // Users create their own purchase records
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;

      // Users update their own records (Triggering Daily ROI), Admin updates all
      allow update: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());
    }

    // TRANSACTIONS
    match /transactions/{txId} {
      // Users see their own, Admin sees all
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());

      // Create Logic:
      // 1. Own transaction (Deposit, Withdrawal, Purchase, ROI, etc.)
      // 2. Referral Commission (Created by the buyer for the upline user)
      // 3. Admin actions (Fiat Approval, Manual Credit, Sweep)
      allow create: if isSignedIn() && (
        request.resource.data.userId == request.auth.uid || 
        request.resource.data.type == 'REFERRAL' ||
        isAdmin()
      );

      // Updates usually reserved for Admin (Approvals)
      allow update: if isAdmin();
    }

    // GIVEAWAY POOLS
    match /giveawayPools/{poolId} {
      allow read: if isSignedIn();
      allow create: if isAdmin();
      // Allow users to increment claims count when claiming, Admin can update everything
      allow update: if isAdmin() || (isSignedIn() && request.resource.data.diff(resource.data).affectedKeys().hasOnly(['claimsCount']));
      allow delete: if isAdmin();
    }

    // GIVEAWAY CLAIMS
    match /giveawayClaims/{claimId} {
      allow read: if isSignedIn() && resource.data.userId == request.auth.uid;
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
    }

    // SYSTEM SETTINGS
    match /system/{docId} {
      allow read: if true;
      allow write: if isAdmin();
    }

    // SYSTEM BANKS (Fiat)
    match /system_banks/{bankId} {
      allow read: if isSignedIn();
      allow write: if isAdmin();
    }

    // FIAT REQUESTS
    match /fiat_requests/{reqId} {
      allow read: if isSignedIn() && (resource.data.userId == request.auth.uid || isAdmin());
      allow create: if isSignedIn() && request.resource.data.userId == request.auth.uid;
      allow update: if isAdmin();
    }

    // VAULT (Admin Keys)
    match /vault/{docId} {
      allow read, write: if isAdmin();
    }
  }
}

